mapper.select:
/** 문제은행 게시판 리스트 */ SELECT a.* ,(select title from t_pass_cert_tpl where pass_idx = a.pass_idx) pass_nm ,(select title from t_pass_cert_tpl where pass_idx = a.compl_idx) compl_nm ,(select user_nm from t_user_info where user_id = a.reg_id) reg_nm FROM t_lecture_subject a where 1=1
ORDER BY REG_DE DESC
LIMIT #{firstIndex},#{rowCnt}
